import{_ as p,c as i}from"./app.f21a7cce.js";const t={},s=i('<h1 id="_51-\u8BB2-\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1" tabindex="-1"><a class="header-anchor" href="#_51-\u8BB2-\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1" aria-hidden="true">#</a> 51 \u8BB2\uFF1A\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\uFF0C\u4ECA\u5929\u6211\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u6DF1\u5165\u6D45\u51FA\u7F51\u7AD9\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1\u3002</p><p>\u76EE\u524D\uFF0C\u5F88\u591A\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u751A\u81F3\u662F\u5F00\u53D1\u5DE5\u7A0B\u5E08\u90FD\u4E00\u76F4\u5206\u4E0D\u6E05\u695A\u53EF\u4F38\u7F29\u6027\u548C\u53EF\u6269\u5C55\u6027\u8FD9\u4E24\u4E2A\u6982\u5FF5\uFF0C\u4E3B\u8981\u539F\u56E0\u662F\u4ECE\u5B57\u9762\u4E0A\u770B\u8FD9\u4E24\u4E2A\u6982\u5FF5\u7684\u786E\u6709\u76F8\u4F3C\u4E4B\u5904\u3002\u4F46\u5B9E\u9645\u60C5\u51B5\u5462\uFF0C\u53EF\u4F38\u7F29\u6027\u548C\u53EF\u6269\u5C55\u6027\u8FD9\u4E24\u4E24\u4E2A\u6982\u5FF5\u7684\u542B\u4E49\u76F8\u5DEE\u5341\u4E07\u516B\u5343\u91CC\uFF0C\u6839\u672C\u4E0D\u5177\u6709\u4EFB\u4F55\u53EF\u6BD4\u6027\u3002</p><p>\u6240\u4EE5\uFF0C\u6211\u5C06\u901A\u8FC7\u4E24\u7BC7\u6587\u7AE0\u6765\u548C\u4F60\u5206\u4EAB\uFF0C\u7F51\u7AD9\u7684\u4F38\u7F29\u6027\u548C\u53EF\u6269\u5C55\u6027\u67B6\u6784\u8BBE\u8BA1\u5230\u5E95\u662F\u4EC0\u4E48\uFF0C\u4EE5\u53CA\u5728\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u65F6\u9700\u8981\u6CE8\u610F\u54EA\u4E9B\u70B9\u3002</p><p><strong>\u53EF\u4F38\u7F29\u6027\u548C\u53EF\u6269\u5C55\u6027\u7684\u6982\u5FF5\u533A\u522B</strong></p><p><strong>\u53EF\u4F38\u7F29\u6027\u7FFB\u8BD1\u81EA Scalability</strong>\uFF0C\u6307\u7684\u662F\u901A\u8FC7\u7B80\u5355\u5730\u589E\u52A0\u786C\u4EF6\u914D\u7F6E\u800C\u4F7F\u670D\u52A1\u5904\u7406\u80FD\u529B\u5448\u7EBF\u6027\u589E\u957F\u7684\u80FD\u529B\u3002\u6700\u7B80\u5355\u76F4\u89C2\u7684\u4F8B\u5B50\uFF0C\u5C31\u662F\u901A\u8FC7\u5728\u5E94\u7528\u670D\u52A1\u5668\u96C6\u7FA4\u4E2D\u589E\u52A0\u66F4\u591A\u7684\u8282\u70B9\uFF0C\u6765\u63D0\u9AD8\u6574\u4E2A\u96C6\u7FA4\u7684\u5904\u7406\u80FD\u529B\u3002</p><p>\u800C<strong>\u53EF\u6269\u5C55\u6027\u7FFB\u8BD1\u81EA Extensibility</strong>\uFF0C\u6307\u7684\u662F\u7F51\u7AD9\u7684\u67B6\u6784\u8BBE\u8BA1\u80FD\u591F\u5FEB\u901F\u9002\u5E94\u9700\u6C42\u7684\u53D8\u5316\uFF0C\u5F53\u9700\u8981\u589E\u52A0\u65B0\u7684\u529F\u80FD\u5B9E\u73B0\u65F6\uFF0C\u5BF9\u539F\u6709\u67B6\u6784\u4E0D\u9700\u8981\u505A\u4FEE\u6539\u6216\u8005\u505A\u5F88\u5C11\u7684\u4FEE\u6539\u5C31\u80FD\u591F\u5FEB\u901F\u6EE1\u8DB3\u65B0\u7684\u4E1A\u52A1\u9700\u6C42\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u5C31\u5148\u548C\u4F60\u5206\u4EAB\u4E0B\u7F51\u7AD9\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784\u3002\u800C\u5173\u4E8E\u7F51\u7AD9\u7684\u53EF\u6269\u5C55\u6027\u67B6\u6784\u8BBE\u8BA1\uFF0C\u6211\u4F1A\u5728\u4E0B\u4E00\u7BC7\u6587\u7AE0\u4E2D\u548C\u4F60\u8BE6\u7EC6\u5206\u4EAB\u3002</p><p><strong>\u5206\u5C42\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784</strong></p><p>\u7F51\u7AD9\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1\u4E3B\u8981\u5305\u542B\u4E24\u4E2A\u5C42\u9762\u7684\u542B\u4E49\uFF1A</p><p>\u4E00\u4E2A\u662F\u6307\uFF0C\u6839\u636E\u529F\u80FD\u8FDB\u884C\u7269\u7406\u5206\u79BB\u6765\u5B9E\u73B0\u4F38\u7F29\uFF1B \u53E6\u4E00\u4E2A\u662F\u6307\uFF0C\u7269\u7406\u5206\u79BB\u540E\u7684\u5355\u4E00\u529F\u80FD\u901A\u8FC7\u589E\u52A0\u6216\u8005\u51CF\u5C11\u786C\u4EF6\u6765\u5B9E\u73B0\u4F38\u7F29\u3002 \u5728\u6839\u636E\u529F\u80FD\u672C\u8EAB\u8FDB\u884C\u7269\u7406\u5206\u79BB\u6765\u5B9E\u73B0\u4F38\u7F29\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u8FD8\u6709\u4E24\u79CD\u4E0D\u540C\u7684\u5B9E\u73B0\u65B9\u5F0F\uFF1A</p><p>\u4E00\u79CD\u662F\u529F\u80FD\u7684\u201C\u6A2A\u5207\u201D\uFF0C\u6BD4\u5982\u4E00\u4E2A\u7535\u5546\u7F51\u7AD9\u7684\u8D2D\u7269\u529F\u80FD\u4ECE\u4E0A\u81F3\u4E0B\u5C31\u53EF\u4EE5\u5206\u4E3A\u754C\u9762 UI \u5C42\u3001\u4E1A\u52A1\u903B\u8F91\u5904\u7406\u5C42\u3001\u516C\u5171\u670D\u52A1\u5C42\u548C\u6570\u636E\u5E93\u5C42\uFF0C\u5982\u679C\u6211\u4EEC\u5C06\u8FD9\u4E9B\u5C42\u533A\u5206\u5F00\u6765\uFF0C\u6BCF\u4E2A\u5C42\u5C31\u53EF\u4EE5\u72EC\u7ACB\u5B9E\u73B0\u53EF\u4F38\u7F29\uFF1B</p><p><img src="https://static001.geekbang.org/resource/image/10/fd/10baabfe5ca950199108c230bce1b5fd.png" alt="\u529F\u80FD\u201C\u6A2A\u5207\u201D\u793A\u610F\u56FE"></p><p>\u53E6\u4E00\u79CD\u662F\u529F\u80FD\u7684\u201C\u7EB5\u5207\u201D\uFF0C\u6BD4\u5982\u4E00\u4E2A\u7535\u5546\u7F51\u7AD9\u53EF\u4EE5\u6839\u636E\u7ECF\u8425\u7684\u4E1A\u52A1\u8303\u56F4\uFF08\u6BD4\u5982\u4E66\u5E97\u3001\u751F\u9C9C\u3001\u5BB6\u7535\u548C\u65E5\u5316\u7528\u54C1\u7B49\uFF09\u8FDB\u884C\u529F\u80FD\u6A21\u5757\u7684\u5212\u5206\uFF0C\u5212\u5206\u540E\u7684\u6BCF\u4E2A\u4E1A\u52A1\u6A21\u5757\u90FD\u53EF\u4EE5\u72EC\u7ACB\u5730\u6839\u636E\u4E1A\u52A1\u6D41\u91CF\u548C\u538B\u529B\u6765\u5B9E\u73B0\u6700\u9002\u5408\u81EA\u5DF1\u89C4\u6A21\u7684\u4F38\u7F29\u6027\u8BBE\u8BA1\u3002</p><p><img src="https://static001.geekbang.org/resource/image/40/c3/40bbc4426be6a8fc2b3c7ae38cd3c7c3.png" alt="\u529F\u80FD\u201C\u7EB5\u5207\u201D\u793A\u610F\u56FE"></p><p>\u540C\u6837\u5730\uFF0C\u5BF9\u4E8E\u5355\u4E00\u529F\u80FD\u53EF\u4EE5\u901A\u8FC7\u589E\u52A0\u6216\u8005\u51CF\u5C11\u786C\u4EF6\u6765\u5B9E\u73B0\u7684\u53EF\u4F38\u7F29\u6027\uFF0C\u4E5F\u6709\u4E24\u79CD\u4E0D\u540C\u7684\u5B9E\u73B0\u65B9\u5F0F\uFF1A</p><ul><li>\u4E00\u79CD\u662F\u7EB5\u5411\u7684\u53EF\u4F38\u7F29\u6027\uFF0C\u6307\u7684\u662F\u901A\u8FC7\u589E\u52A0\u5355\u4E00\u670D\u52A1\u5668\u4E0A\u7684\u786C\u4EF6\u8D44\u6E90\u6765\u63D0\u9AD8\u5904\u7406\u80FD\u529B\u3002\u6BD4\u5982\uFF0C\u5728\u73B0\u6709\u670D\u52A1\u5668\u4E0A\u589E\u52A0 CPU\u3001\u5185\u5B58\uFF0C\u6216\u8005\u5728\u73B0\u6709\u7684 RAID/SAN \u5B58\u50A8\u4E2D\u589E\u52A0\u786C\u76D8\u7B49\u3002 \u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\u4F7F\u7528\u7684\u201C\u5BA0\u7269\u201D\u6A21\u5F0F\uFF0C\u5C31\u662F\u901A\u8FC7\u8FD9\u4E2A\u601D\u8DEF\u6765\u5B9E\u73B0\u6709\u9650\u7684\u53EF\u4F38\u7F29\u6027\uFF0C\u6211\u4EEC\u5F80\u5F80\u628A\u8FD9\u79CD\u65B9\u5F0F\u7684\u4F38\u7F29\u6027\u79F0\u4E3A\u5355\u8282\u70B9\u7684\u53EF\u4F38\u7F29\u6027\u3002\u663E\u7136\uFF0C\u5728\u5982\u4ECA\u6D77\u91CF\u4E92\u8054\u7F51\u6D41\u91CF\u7684\u60C5\u51B5\u4E0B\uFF0C\u60F3\u4EC5\u4EC5\u4F9D\u8D56\u4E8E\u67D0\u4E00\u53F0\u670D\u52A1\u5668\u6765\u5904\u7406\u5404\u79CD\u8BF7\u6C42\u663E\u7136\u662F\u4E0D\u53EF\u80FD\u7684\u3002</li><li>\u53E6\u4E00\u79CD\u662F\u6A2A\u5411\u7684\u53EF\u4F38\u7F29\u6027\uFF0C\u6307\u7684\u662F\u901A\u8FC7\u4F7F\u7528\u670D\u52A1\u5668\u96C6\u7FA4\u6765\u5B9E\u73B0\u5355\u4E00\u529F\u80FD\u7684\u53EF\u6269\u5C55\u6027\u3002\u5F53\u4E00\u53F0\u673A\u5668\u4E0D\u8DB3\u4EE5\u5904\u7406\u5927\u91CF\u7528\u6237\u5E76\u53D1\u8BF7\u6C42\u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u5C31\u91C7\u7528\u591A\u53F0\u673A\u5668\u7EC4\u6210\u96C6\u7FA4\u6765\u5171\u540C\u8D1F\u62C5\u5E76\u53D1\u538B\u529B\u3002 \u8FD9\u79CD\u65B9\u5F0F\u662F\u57FA\u4E8E\u96C6\u7FA4\u7684\u53EF\u4F38\u7F29\u6027\u5B9E\u73B0\u7684\uFF0C\u4E5F\u662F\u76EE\u524D\u6700\u4E3B\u6D41\u7684\u7F51\u7AD9\u53EF\u4F38\u7F29\u6027\u65B9\u6CD5\uFF0C\u4E5F\u5C31\u662F\u6211\u4E4B\u524D\u63D0\u5230\u8FC7\u7684\u201C\u7272\u53E3\u201D\u6A21\u5F0F\u3002\u5F88\u591A\u65F6\u5019\u5F53\u6211\u4EEC\u8C08\u53CA\u7F51\u7AD9\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1\u65F6\uFF0C\u5982\u679C\u6CA1\u6709\u7279\u5B9A\u7684\u4E0A\u4E0B\u6587\u6216\u8005\u7279\u6307\u7684\u573A\u666F\uFF0C\u5F80\u5F80\u6307\u7684\u90FD\u662F\u57FA\u4E8E\u96C6\u7FA4\u7684\u53EF\u4F38\u7F29\u6027\u3002</li></ul><p><img src="https://static001.geekbang.org/resource/image/28/ba/289556cf89912d61408967bba1baafba.png" alt="\u5355\u4E00\u529F\u80FD\u901A\u8FC7\u589E\u52A0\u6216\u8005\u51CF\u5C11\u786C\u4EF6\u6765\u5B9E\u73B0\u7684\u53EF\u4F38\u7F29\u6027"></p><p>\u57FA\u4E8E\u96C6\u7FA4\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1\uFF0C\u662F\u548C\u7F51\u7AD9\u672C\u8EAB\u7684\u5206\u5C42\u67B6\u6784\u8BBE\u8BA1\u76F8\u5BF9\u5E94\u7684\uFF1A</p><ul><li>\u5728\u5E94\u7528\u670D\u52A1\u5668\u5C42\u9762\u6709\u5E94\u7528\u670D\u52A1\u5668\u96C6\u7FA4\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1\uFF1B</li><li>\u5728\u7F13\u5B58\u670D\u52A1\u5668\u5C42\u9762\u6709\u7F13\u5B58\u670D\u52A1\u5668\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1\uFF1B</li><li>\u5728\u6570\u636E\u5E93\u5C42\u9762\u6709\u6570\u636E\u5E93\u670D\u52A1\u5668\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1\u3002</li></ul><p>\u867D\u7136\u90FD\u662F\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1\uFF0C\u4F46\u662F\u7531\u4E8E\u5E94\u7528\u670D\u52A1\u5668\u3001\u7F13\u5B58\u670D\u52A1\u5668\u548C\u6570\u636E\u5E93\u670D\u52A1\u5668\u672C\u8EAB\u7684\u67B6\u6784\u5728\u8BBE\u8BA1\u4E0A\u5C31\u6709\u6240\u533A\u522B\uFF0C\u52A0\u4E4B\u5B83\u4EEC\u7684\u4F7F\u7528\u573A\u666F\u4E0D\u540C\uFF0C\u4F7F\u5F97\u5B83\u4EEC\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1\u5C31\u6709\u7740\u5DE8\u5927\u7684\u5DEE\u5F02\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u5C31\u5148\u7B80\u5355\u89E3\u91CA\u4E00\u4E0B\u8FD9\u4E09\u4E2A\u5C42\u9762\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1\u6307\u7684\u662F\u4EC0\u4E48\uFF0C\u4EE5\u53CA\u4ECE\u6D4B\u8BD5\u4EBA\u5458\u7684\u89D2\u5EA6\u6765\u770B\u6211\u4EEC\u9700\u8981\u5173\u6CE8\u54EA\u4E9B\u70B9\u3002</p><p><strong>\u5E94\u7528\u670D\u52A1\u5668\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1</strong></p><p>\u5E94\u7528\u670D\u52A1\u5668\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1\u662F\u6700\u76F4\u89C2\uFF0C\u4E5F\u662F\u6700\u5BB9\u6613\u7406\u89E3\u7684\u3002\u5F53\u4E00\u53F0\u5E94\u7528\u670D\u52A1\u5668\u4E0D\u8DB3\u4EE5\u652F\u6491\u4E1A\u52A1\u6D41\u91CF\u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u5C31\u53EF\u4EE5\u7528\u591A\u53F0\u670D\u52A1\u5668\u6765\u5206\u62C5\u4E1A\u52A1\u6D41\u91CF\u3002</p><p>\u4F46\u662F\uFF0C\u4E3A\u4E86\u4FDD\u8BC1\u8FD9\u6279\u670D\u52A1\u5668\u5BF9\u5916\u66B4\u9732\u7684\u662F\u4E00\u4E2A\u7EDF\u4E00\u7684\u8282\u70B9\uFF0C\u6211\u4EEC\u5C31\u9700\u8981\u4E00\u4E2A\u8D1F\u8F7D\u5747\u8861\u5668\u4F5C\u4E3A\u7EDF\u4E00\u7684\u7A97\u53E3\u6765\u5BF9\u5916\u63D0\u4F9B\u670D\u52A1\uFF0C\u540C\u65F6\u8D1F\u8F7D\u5747\u8861\u5668\u4F1A\u628A\u5B9E\u9645\u7684\u4E1A\u52A1\u8BF7\u6C42\u8F6C\u53D1\u7ED9\u96C6\u7FA4\u4E2D\u7684\u673A\u5668\u53BB\u5177\u4F53\u6267\u884C\u3002</p><p>\u8FD9\u91CC\u9700\u8981\u7279\u522B\u6CE8\u610F\u7684\u662F\uFF0C\u8D1F\u8F7D\u5747\u8861\u5668\u5E76\u4E0D\u662F\u6309\u7167\u4F60\u5728\u5B57\u9762\u4E0A\u7406\u89E3\u7684\u201C\u5747\u8861\u201D\u90A3\u6837\uFF0C\u628A\u4E1A\u52A1\u8D1F\u8F7D\u5E73\u5747\u5206\u914D\u5230\u96C6\u7FA4\u4E2D\u7684\u5404\u4E2A\u8282\u70B9\uFF0C\u800C\u662F\u901A\u8FC7\u8D1F\u8F7D\u5747\u8861\u7B97\u6CD5\uFF08\u6BD4\u5982\u8F6E\u8BE2\u7B97\u6CD5\u3001\u57FA\u4E8E\u52A0\u6743\u7684\u8F6E\u8BE2\u7B97\u6CD5\u3001\u6700\u5C0F\u94FE\u63A5\u7B97\u6CD5\u7B49\uFF09\u5C06\u7528\u6237\u6D41\u91CF\u5206\u914D\u5230\u96C6\u7FA4\u673A\u5668\u3002\u4ECE\u8FD9\u4E2A\u610F\u4E49\u4E0A\u8BF4\uFF0C<strong>\u5C06\u8D1F\u8F7D\u5747\u8861\u5668\u79F0\u4E3A\u4EFB\u52A1\u5206\u914D\u5668\u624D\u66F4\u5408\u9002</strong>\u3002</p><p><img src="https://static001.geekbang.org/resource/image/03/ba/035f500a8526b34c66e3f1fd7e42c0ba.png" alt="\u901A\u8FC7\u8D1F\u8F7D\u5747\u8861\u5668\u5B9E\u73B0\u7684\u5E94\u7528\u670D\u52A1\u5668\u96C6\u7FA4\u793A\u610F\u56FE"></p><p>\u4E3A\u4E86\u5B9E\u73B0\u7EBF\u6027\u53EF\u4F38\u7F29\u6027\uFF0C\u6211\u4EEC\u5E0C\u671B\u5E94\u7528\u672C\u8EAB\u662F\u65E0\u72B6\u6001\u7684\u3002\u6B64\u65F6\uFF0C\u4EFB\u4F55\u8BF7\u6C42\u90FD\u53EF\u4EE5\u5728\u96C6\u7FA4\u4E2D\u4EFB\u610F\u8282\u70B9\u4E0A\u6765\u6267\u884C\uFF0C\u4E5F\u5C31\u662F\u8BF4\u96C6\u7FA4\u7684\u5904\u7406\u80FD\u529B\u5C06\u968F\u7740\u8282\u70B9\u6570\u91CF\u7684\u589E\u591A\u5448\u73B0\u7EBF\u6027\u589E\u957F\u7684\u6001\u52BF\u3002</p><p>\u4F46\u662F\uFF0C\u5982\u679C\u5E94\u7528\u672C\u8EAB\u662F\u6709\u72B6\u6001\u7684\uFF0C\u90A3\u4E48\u5C31\u4F1A\u8981\u6C42\u57FA\u4E8E\u4E00\u6B21\u4F1A\u8BDD\uFF08session\uFF09\u7684\u591A\u6B21\u8BF7\u6C42\u90FD\u88AB\u5206\u914D\u5230\u96C6\u7FA4\u4E2D\u67D0\u4E00\u53F0\u56FA\u5B9A\u7684\u670D\u52A1\u5668\u4E0A\u53BB\u6267\u884C\u3002</p><p>\u7406\u89E3\u4E86\u4E0A\u8FF0\u5E94\u7528\u670D\u52A1\u5668\u96C6\u7FA4\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784\u539F\u7406\u540E\uFF0C\u6211\u4EEC\u518D\u4ECE\u6D4B\u8BD5\u4EBA\u5458\u7684\u89D2\u5EA6\u6765\u60F3\u60F3\uFF0C\u5E94\u8BE5\u8003\u8651\u54EA\u4E9B\u76F8\u5173\u7684\u6D4B\u8BD5\u573A\u666F\u3002\u4E3A\u6B64\uFF0C\u6211\u603B\u7ED3\u4E86\u4EE5\u4E0B\u51E0\u70B9\u4F9B\u4F60\u53C2\u8003\uFF1A</p><ul><li>\u9700\u8981\u901A\u8FC7\u538B\u529B\u6D4B\u8BD5\u6765\u5F97\u51FA\u5355\u4E00\u8282\u70B9\u7684\u8D1F\u8F7D\u627F\u53D7\u80FD\u529B\uFF1B</li><li>\u9A8C\u8BC1\u7CFB\u7EDF\u6574\u4F53\u7684\u8D1F\u8F7D\u627F\u53D7\u80FD\u529B\uFF0C\u662F\u5426\u80FD\u591F\u968F\u7740\u96C6\u7FA4\u4E2D\u7684\u8282\u70B9\u6570\u91CF\u5448\u73B0\u7EBF\u6027\u589E\u957F\uFF1B</li><li>\u96C6\u7FA4\u4E2D\u8282\u70B9\u7684\u6570\u91CF\u662F\u5426\u6709\u4E0A\u9650\uFF1B</li><li>\u65B0\u52A0\u5165\u7684\u8282\u70B9\u662F\u5426\u53EF\u4EE5\u63D0\u4F9B\u548C\u539F\u6765\u8282\u70B9\u65E0\u5DEE\u5F02\u7684\u670D\u52A1\uFF1B</li><li>\u5BF9\u4E8E\u6709\u72B6\u6001\u7684\u5E94\u7528\uFF0C\u662F\u5426\u80FD\u591F\u5B9E\u73B0\u4E00\u6B21\u4F1A\u8BDD\uFF08session\uFF09\u7684\u591A\u6B21\u8BF7\u6C42\u90FD\u88AB\u5206\u914D\u5230\u96C6\u7FA4\u4E2D\u67D0\u4E00\u53F0\u56FA\u5B9A\u7684\u670D\u52A1\u5668\u4E0A\uFF1B</li><li>\u9A8C\u8BC1\u8D1F\u8F7D\u5747\u8861\u7B97\u6CD5\u7684\u51C6\u786E\u6027\u3002</li></ul><p><strong>\u7F13\u5B58\u96C6\u7FA4\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1</strong></p><p>\u7F13\u5B58\u96C6\u7FA4\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1\uFF0C\u76F8\u6BD4\u5E94\u7528\u670D\u52A1\u5668\u96C6\u7FA4\u8981\u590D\u6742\u5F97\u591A\u3002</p><p><strong>\u4F20\u7EDF\u7684\u7F13\u5B58\u670D\u52A1\u5668\u96C6\u7FA4\u662F\u65E0\u6CD5\u901A\u8FC7\u7B80\u5355\u5730\u52A0\u5165\u65B0\u7684\u8282\u70B9\u6765\u5B9E\u73B0\u6269\u5BB9\u7684</strong>\uFF0C\u5176\u4E2D\u7684\u6839\u672C\u539F\u56E0\uFF0C\u5C31\u8981\u4ECE\u7F13\u5B58\u7684\u6838\u5FC3\u539F\u7406\u5F00\u59CB\u8BB2\u8D77\u4E86\u3002</p><p>\u5047\u5B9A\uFF0C\u4E00\u4E2A\u7F13\u5B58\u96C6\u7FA4\u4E2D\u6709 3 \u53F0\u673A\u5668\uFF0C\u90A3\u4E48\u6211\u4EEC\u5728\u5C06\u9700\u8981\u7F13\u5B58\u7684\u5185\u5BB9\u5B58\u5165\u7F13\u5B58\u96C6\u7FA4\u7684\u8FC7\u7A0B\uFF0C\u5305\u62EC\u4E86\u8FD9\u4E09\u6B65\uFF1A</p><p>\u9996\u5148\uFF0C\u5C06\u9700\u8981\u7F13\u5B58\u7684\u5185\u5BB9\u7684 Key \u503C\u505A Hash \u8FD0\u7B97\uFF1B \u7136\u540E\uFF0C\u5C06\u5F97\u5230\u7684 Hash \u503C\u5BF9 3 \u53D6\u4F59\u6570\uFF1B \u6700\u540E\uFF0C\u5C06\u7F13\u5B58\u5185\u5BB9\u5199\u5165\u4F59\u6570\u6240\u4EE3\u8868\u7684\u90A3\u53F0\u670D\u52A1\u5668\u3002 \u800C\u6B64\u65F6\uFF0C\u5982\u679C\u6211\u4EEC\u5728\u7F13\u5B58\u96C6\u7FA4\u4E2D\u52A0\u5165\u4E86\u4E00\u53F0\u65B0\u7684\u673A\u5668\uFF0C\u4E5F\u5C31\u662F\u8BF4\u7F13\u5B58\u96C6\u7FA4\u4E2D\u673A\u5668\u7684\u6570\u91CF\u53D8\u6210\u4E86 4\u3002\u8FD9\u65F6 Key \u7684 Hash \u503C\u5C31\u5E94\u8BE5\u5BF9 4 \u53D6\u4F59\uFF0C\u4F60\u4F1A\u53D1\u73B0\u8FD9\u4E48\u4E00\u6765\uFF0C\u539F\u672C\u5DF2\u7ECF\u7F13\u5B58\u7684\u7EDD\u5927\u591A\u6570\u5185\u5BB9\u5C31\u90FD\u5931\u6548\u4E86\uFF0C\u5FC5\u987B\u91CD\u6784\u6574\u4E2A\u7F13\u5B58\u96C6\u7FA4\u3002\u800C\u8FD9\uFF0C\u663E\u7136\u4E0D\u80FD\u88AB\u63A5\u53D7\u3002</p><p>\u4E3A\u4E86\u89E3\u51B3\u4E0A\u8FF0\u8FD9\u4E2A\u95EE\u9898\uFF0C\u4F7F\u5F97\u7F13\u5B58\u96C6\u7FA4\u4E5F\u53EF\u4EE5\u505A\u5230\u6309\u9700\u3001\u9AD8\u6548\u5730\u4F38\u7F29\uFF0C\u90A3\u5C31\u5FC5\u987B\u91C7\u7528\u66F4\u4E3A\u5148\u8FDB\u7684 Hash \u4E00\u81F4\u6027\u7B97\u6CD5\u3002\u8FD9\u4E2A\u7B97\u6CD5\u53EF\u4EE5\u5F88\u5DE7\u5999\u5730\u89E3\u51B3\u7F13\u5B58\u96C6\u7FA4\u7684\u6269\u5BB9\u95EE\u9898\uFF0C\u4FDD\u8BC1\u4E86\u65B0\u589E\u673A\u5668\u8282\u70B9\u7684\u65F6\u5019\u5927\u90E8\u5206\u7684\u7F13\u5B58\u4E0D\u4F1A\u5931\u6548\u3002</p><p>\u5982\u679C\u4F60\u60F3\u4E86\u89E3 Hash \u4E00\u81F4\u6027\u7B97\u6CD5\u66F4\u8BE6\u7EC6\u7684\u7EC6\u8282\uFF0C\u8BF7\u81EA\u884C\u767E\u5EA6\u3002</p><p>\u540C\u6837\u5730\uFF0C\u77E5\u9053\u4E86\u7F13\u5B58\u96C6\u7FA4\u6269\u5BB9\u7684\u5B9E\u73B0\u7EC6\u8282\u540E\uFF0C\u6211\u4EEC\u518D\u4ECE\u6D4B\u8BD5\u4EBA\u5458\u7684\u89D2\u5EA6\u51FA\u53D1\uFF0C\u770B\u770B\u9700\u8981\u989D\u5916\u5173\u6CE8\u54EA\u4E9B\u70B9\u3002\u8FD9\u91CC\uFF0C\u6211\u603B\u7ED3\u4E86\u4EE5\u4E0B\u51E0\u70B9\u4F9B\u4F60\u53C2\u8003\uFF1A</p><ul><li>\u9488\u5BF9\u7F13\u5B58\u96C6\u7FA4\u4E2D\u65B0\u589E\u8282\u70B9\u7684\u6D4B\u8BD5\uFF0C\u9A8C\u8BC1\u5176\u5BF9\u539F\u6709\u7F13\u5B58\u7684\u5F71\u54CD\u662F\u5426\u8DB3\u591F\u5C0F\uFF1B</li><li>\u9A8C\u8BC1\u7CFB\u7EDF\u51B7\u542F\u52A8\u5B8C\u6210\u540E\uFF0C\u7F13\u5B58\u4E2D\u8FD8\u6CA1\u6709\u4EFB\u4F55\u6570\u636E\u7684\u65F6\u5019\uFF0C\u5982\u679C\u6B64\u65F6\u7F51\u7AD9\u8D1F\u8F7D\u8F83\u5927\uFF0C\u6570\u636E\u5E93\u662F\u5426\u53EF\u4EE5\u627F\u53D7\u8FD9\u6837\u7684\u538B\u529B\uFF1B</li><li>\u9700\u8981\u9A8C\u8BC1\u5404\u79CD\u60C5\u51B5\u4E0B\uFF0C\u7F13\u5B58\u6570\u636E\u548C\u6570\u636E\u5E93\u6570\u636E\u7684\u4E00\u81F4\u6027\uFF1B</li><li>\u9A8C\u8BC1\u662F\u5426\u5DF2\u7ECF\u5BF9\u6F5C\u5728\u7684\u7F13\u5B58\u7A7F\u900F\u653B\u51FB\u8FDB\u884C\u4E86\u5904\u7406\uFF0C\u56E0\u4E3A\u5982\u679C\u6709\u4EBA\u523B\u610F\u5229\u7528\u8FD9\u4E2A\u6F0F\u6D1E\u6765\u53D1\u8D77\u6D77\u91CF\u8BF7\u6C42\u7684\u8BDD\uFF0C\u5C31\u6709\u53EF\u80FD\u4F1A\u62D6\u57AE\u6570\u636E\u5E93\u3002</li></ul><p><strong>\u6570\u636E\u5E93\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1</strong></p><p>\u4ECE\u5B9E\u9645\u5E94\u7528\u7684\u89D2\u5EA6\u6765\u770B\uFF0C\u6570\u636E\u5E93\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1\u4E3B\u8981\u6709\u56DB\u79CD\u65B9\u5F0F\uFF1A</p><p><strong>\u7B2C\u4E00\u79CD\u65B9\u5F0F\u662F\u76EE\u524D\u6700\u5E38\u7528\u7684\u4E1A\u52A1\u5206\u5E93</strong>\uFF0C\u4E5F\u5C31\u662F\u4ECE\u4E1A\u52A1\u4E0A\u5C06\u4E00\u4E2A\u5E9E\u5927\u7684\u6570\u636E\u5E93\u62C6\u5206\u6210\u591A\u4E2A\u4E0D\u540C\u7684\u6570\u636E\u5E93\u3002\u6BD4\u5982\uFF0C\u5BF9\u4E8E\u7535\u5546\u7F51\u7AD9\u6765\u8BF4\uFF0C\u5B83\u4EEC\u53EF\u4EE5\u8003\u8651\u5C06\u7528\u6237\u76F8\u5173\u7684\u8868\u653E\u5728\u4E00\u4E2A\u6570\u636E\u5E93\u4E2D\uFF0C\u800C\u5546\u54C1\u76F8\u5173\u7684\u8868\u653E\u5728\u53E6\u4E00\u4E2A\u6570\u636E\u5E93\u4E2D\u3002</p><p>\u8FD9\u79CD\u65B9\u5F0F\u672C\u8EAB\u4E5F\u7B26\u5408\u6A21\u5757\u8BBE\u8BA1\u5206\u800C\u6CBB\u4E4B\u7684\u601D\u60F3\uFF0C\u4F46\u6700\u5927\u7684\u95EE\u9898\u662F\u8DE8\u6570\u636E\u5E93\u6570\u636E\u7684 join \u64CD\u4F5C\u53EA\u80FD\u901A\u8FC7\u4EE3\u7801\u5728\u5185\u5B58\u4E2D\u5B8C\u6210\uFF0C\u5B9E\u73B0\u4EE3\u4EF7\u548C\u6210\u672C\u90FD\u6BD4\u8F83\u9AD8\u3002\u8FD9\u79CD\u65B9\u5F0F\u76EE\u524D\u5728\u4E00\u4E9B\u4E2D\u5927\u578B\u7535\u5546\u6709\u4E0D\u540C\u7A0B\u5EA6\u7684\u5E94\u7528\u3002</p><p><strong>\u7B2C\u4E8C\u79CD\u65B9\u5F0F\u662F\u8BFB\u5199\u5206\u79BB\u7684\u6570\u636E\u5E93\u8BBE\u8BA1</strong>\uFF0C\u5176\u4E2D\u4E3B\u5E93\u7528\u4E8E\u6240\u6709\u7684\u5199\u64CD\u4F5C\uFF0C\u4ECE\u5E93\u7528\u4E8E\u6240\u6709\u7684\u8BFB\u64CD\u4F5C\uFF0C\u7136\u540E\u4E3B\u4ECE\u5E93\u4F1A\u81EA\u52A8\u8FDB\u884C\u6570\u636E\u540C\u6B65\u64CD\u4F5C\u3002\u8FD9\u6837\u4E00\u6765\uFF0C\u4E3B\u5E93\u5C31\u53EF\u4EE5\u6839\u636E\u5199\u64CD\u4F5C\u6765\u4F18\u5316\u6027\u80FD\uFF0C\u800C\u4ECE\u5E93\u5C31\u53EF\u4EE5\u6839\u636E\u8BFB\u64CD\u4F5C\u6765\u4F18\u5316\u6027\u80FD\u3002</p><p>\u4F46\u662F\uFF0C\u8FD9\u4E2A\u67B6\u6784\u6700\u5927\u7684\u95EE\u9898\u5728\u4E8E\u53EF\u80FD\u51FA\u73B0\u6570\u636E\u4E0D\u4E00\u81F4\u7684\u60C5\u51B5\u3002\u6BD4\u5982\uFF0C\u5199\u5165\u7684\u6570\u636E\u6CA1\u80FD\u53CA\u65F6\u540C\u6B65\u5230\u4ECE\u5E93\uFF0C\u5C31\u53EF\u80FD\u4F1A\u51FA\u73B0\u6570\u636E\u4E0D\u4E00\u81F4\u3002\u53E6\u5916\uFF0C\u8FD9\u79CD\u8BFB\u5199\u5206\u79BB\u7684\u8BBE\u8BA1\u5BF9\u6570\u636E\u5E93\u53EF\u4F38\u7F29\u6027\u7684\u8D21\u732E\u6765\u8BB2\uFF0C\u6BD4\u8F83\u6709\u9650\uFF0C\u5F88\u96BE\u4ECE\u6839\u672C\u4E0A\u89E3\u51B3\u95EE\u9898\u3002</p><p>\u8FD9\u79CD\u65B9\u5F0F\u4E3B\u8981\u5E94\u7528\u5728\u4E2D\u5C0F\u578B\u89C4\u6A21\u7684\u7F51\u7AD9\u4E2D\uFF0C\u540C\u65F6\u8BFB\u5199\u5206\u79BB\u7684\u8BBE\u8BA1\u4E5F\u901A\u5E38\u4F1A\u548C\u4E1A\u52A1\u5206\u5E93\u7684\u8BBE\u8BA1\u4E00\u8D77\u91C7\u7528\uFF0C\u6765\u63D0\u9AD8\u4E1A\u52A1\u5206\u5E93\u540E\u7684\u6570\u636E\u5E93\u6027\u80FD\u3002</p><p>\u4E3A\u4E86\u8FDB\u4E00\u6B65\u63D0\u9AD8\u6570\u636E\u5E93\u7684\u53EF\u4F38\u7F29\u6027\uFF0C\u4E8E\u662F\u5C31\u51FA\u73B0\u4E86<strong>\u7B2C\u4E09\u79CD\u6570\u636E\u5E93\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1\uFF1A\u5206\u5E03\u5F0F\u6570\u636E\u5E93</strong>\u3002\u5206\u5E03\u5F0F\u6570\u636E\u5E93\u540C\u6837\u5B58\u5728\u6570\u636E\u4E0D\u4E00\u81F4\u7684\u95EE\u9898\uFF0C\u5E76\u4E14\uFF0C\u8FD9\u4E2A\u65B9\u6CD5\u901A\u5E38\u53EA\u5728\u5355\u4E2A\u6570\u636E\u8868\u5F02\u5E38\u5E9E\u5927\u7684\u65F6\u5019\u624D\u4F1A\u88AB\u91C7\u7528\uFF0C\u5426\u5219\u6211\u8FD8\u662F\u66F4\u63A8\u8350\u4E1A\u52A1\u5206\u5E93\u7684\u65B9\u6CD5\u3002\u8FD9\u79CD\u6570\u636E\u5E93\u8BBE\u8BA1\u53EF\u4EE5\u8BF4\u662F\u6BD4\u8F83\u4E3B\u6D41\u7684\u5E94\u5BF9\u5927\u89C4\u6A21\u9AD8\u5E76\u53D1\u5E94\u7528\u7684\u6570\u636E\u5E93\u65B9\u6848\u3002</p><p><strong>\u7B2C\u56DB\u79CD\u65B9\u5F0F\u5219\u662F\u5B8C\u5168\u98A0\u8986\u4E86\u4F20\u7EDF\u5173\u7CFB\u578B\u6570\u636E\u6570\u636E\u5E93\u7684 NoSQL \u8BBE\u8BA1</strong>\u3002NoSQL \u653E\u5F03\u4E86\u4E8B\u52A1\u4E00\u81F4\u6027\uFF0C\u5E76\u4E14\u5929\u751F\u5C31\u662F\u4E3A\u4E86\u53EF\u4F38\u7F29\u6027\u800C\u8BBE\u8BA1\u7684\uFF0C\u6240\u4EE5\u5728\u53EF\u4F38\u7F29\u6027\u65B9\u9762\u5177\u6709\u5929\u7136\u4F18\u52BF\u3002\u56E0\u6B64\uFF0C\u5728\u4E92\u8054\u7F51\u9886\u57DF\u88AB\u5E7F\u6CDB\u4F7F\u7528\u3002</p><p>\u4ECE\u6D4B\u8BD5\u7684\u89D2\u5EA6\u51FA\u53D1\uFF0C\u65E0\u8BBA\u662F\u6570\u636E\u5E93\u67B6\u6784\u54EA\u79CD\u8BBE\u8BA1\uFF0C\u6211\u4EEC\u4E00\u822C\u90FD\u4F1A\u4ECE\u4EE5\u4E0B\u51E0\u4E2A\u65B9\u9762\u6765\u8003\u8651\u6D4B\u8BD5\u7528\u4F8B\u7684\u8BBE\u8BA1\uFF1A</p><ul><li>\u6B63\u786E\u8BFB\u53D6\u5230\u521A\u5199\u5165\u6570\u636E\u7684\u5EF6\u8FDF\u65F6\u95F4\uFF1B</li><li>\u5728\u6570\u636E\u5E93\u67B6\u6784\u53D1\u751F\u6539\u53D8\uFF0C\u6216\u8005\u540C\u6837\u7684\u67B6\u6784\u6570\u636E\u5E93\u53C2\u6570\u53D1\u751F\u4E86\u6539\u53D8\u65F6\uFF0C\u6570\u636E\u5E93\u57FA\u51C6\u6027\u80FD\u662F\u5426\u4F1A\u53D1\u751F\u660E\u663E\u7684\u53D8\u5316\uFF1B</li><li>\u538B\u529B\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\uFF0C\u6570\u636E\u5E93\u670D\u52A1\u5668\u7684\u5404\u9879\u76D1\u63A7\u6307\u6807\u662F\u5426\u7B26\u5408\u9884\u671F\uFF1B</li><li>\u6570\u636E\u5E93\u5728\u7EBF\u6269\u5BB9\u8FC7\u7A0B\u4E2D\u5BF9\u4E1A\u52A1\u7684\u5F71\u54CD\u7A0B\u5EA6\uFF1B</li><li>\u6570\u636E\u5E93\u96C6\u7FA4\u4E2D\uFF0C\u67D0\u4E2A\u8282\u70B9\u7531\u4E8E\u786C\u4EF6\u6545\u969C\u5BF9\u4E1A\u52A1\u7684\u5F71\u54CD\u7A0B\u5EA6\u3002</li></ul><p><strong>\u603B\u7ED3</strong></p><p>\u9996\u5148\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u53EF\u4F38\u7F29\u6027\u7FFB\u8BD1\u81EA Scalability\uFF0C\u800C\u53EF\u6269\u5C55\u6027\u7FFB\u8BD1\u81EA Extensibility\uFF0C\u4ECE\u82F1\u6587\u5355\u8BCD\u7684\u542B\u4E49\u4E0A\u6211\u4EEC\u5C31\u53EF\u4EE5\u770B\u51FA\u8FD9\u4E24\u4E2A\u6982\u5FF5\u95F4\u7684\u5DEE\u5F02\u4E86\u3002</p><p>\u5728\u6211\u770B\u6765\uFF0C\u7F51\u7AD9\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1\u4E3B\u8981\u5305\u542B\u4E24\u4E2A\u5C42\u9762\u7684\u542B\u4E49\uFF0C\u4E00\u4E2A\u662F\u6307\u6839\u636E\u529F\u80FD\u8FDB\u884C\u7269\u7406\u5206\u79BB\u6765\u5B9E\u73B0\u4F38\u7F29\uFF0C\u53E6\u4E00\u4E2A\u662F\u6307\u7269\u7406\u5206\u79BB\u540E\u7684\u5355\u4E00\u529F\u80FD\u901A\u8FC7\u589E\u52A0\u6216\u8005\u51CF\u5C11\u786C\u4EF6\u6765\u5B9E\u73B0\u4F38\u7F29\u3002</p><p>\u4ECE\u6574\u4F53\u67B6\u6784\u7684\u89D2\u5EA6\u6765\u770B\uFF0C\u5E94\u7528\u670D\u52A1\u5668\u3001\u7F13\u5B58\u96C6\u7FA4\u548C\u6570\u636E\u5E93\u670D\u52A1\u5668\u5404\u81EA\u90FD\u6709\u9002\u5408\u81EA\u5DF1\u7684\u53EF\u4F38\u7F29\u6027\u8BBE\u8BA1\u7B56\u7565\uFF1A\u5E94\u7528\u670D\u52A1\u5668\u4E3B\u8981\u901A\u8FC7\u96C6\u7FA4\u6765\u5B9E\u73B0\u53EF\u4F38\u7F29\u6027\uFF0C\u7F13\u5B58\u96C6\u7FA4\u4E3B\u8981\u901A\u8FC7 Hash \u4E00\u81F4\u6027\u7B97\u6CD5\u6765\u5B9E\u73B0\uFF0C\u6570\u636E\u5E93\u53EF\u4EE5\u901A\u8FC7\u4E1A\u52A1\u5206\u5E93\u3001\u8BFB\u5199\u5206\u79BB\u3001\u5206\u5E03\u5F0F\u6570\u636E\u5E93\u4EE5\u53CA NoSQL \u6765\u5B9E\u73B0\u53EF\u4F38\u7F29\u6027\u3002</p><p>\u800C\u76F8\u5E94\u7684\u7406\u89E3\u4E86\u7F51\u7AD9\u7684\u53EF\u4F38\u7F29\u6027\u67B6\u6784\u8BBE\u8BA1\u540E\uFF0C\u6211\u4EEC\u5728\u5F00\u5C55\u6D4B\u8BD5\u65F6\uFF0C\u5C31\u53EF\u4EE5\u975E\u5E38\u81EA\u4FE1\u5730\u8BBE\u8BA1\u51FA\u6709\u9488\u5BF9\u6027\u7684\u6D4B\u8BD5\u7528\u4F8B\u4E86\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u6240\u63A5\u89E6\u7684\u88AB\u6D4B\u7CFB\u7EDF\uFF0C\u662F\u5426\u91C7\u7528\u4E86\u53EF\u4F38\u7F29\u6027\u7684\u67B6\u6784\u8BBE\u8BA1\u65B9\u6848\uFF1F\u5728\u5177\u4F53\u5F00\u5C55\u6D4B\u8BD5\u7684\u65F6\u5019\uFF0C\u4F60\u53C8\u662F\u5982\u4F55\u8BBE\u8BA1\u6D4B\u8BD5\u7528\u4F8B\u7684\u5462\uFF1F</p>',58);function l(r,a){return s}var n=p(t,[["render",l],["__file","51.html.vue"]]);export{n as default};
